package main

import (
	"log"
	"net/http"
	"os"
	"regexp"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	validLabel = regexp.MustCompile(`^[a-zA-Z0-9_-]{1,64}$`)

	requests = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "app_requests_total",
			Help: "Total number of requests processed.",
		},
		[]string{"user", "endpoint"},
	)
)

func init() {
	prometheus.MustRegister(requests)
}

func validateLabel(label string) bool {
	return validLabel.MatchString(label)
}

func recordMetrics(user, endpoint string) {
	if !validateLabel(user) || !validateLabel(endpoint) {
		log.Println("Invalid label value")
		return
	}
	requests.With(prometheus.Labels{"user": user, "endpoint": endpoint}).Inc()
}

func handler(w http.ResponseWriter, r *http.Request) {
	user := r.URL.Query().Get("user")
	endpoint := r.URL.Query().Get("endpoint")

	if user == "" || endpoint == "" {
		http.Error(w, "Missing user or endpoint", http.StatusBadRequest)
		return
	}

	recordMetrics(user, endpoint)
	w.Write([]byte("Metrics recorded"))
}

func main() {
	http.Handle("/metrics", promhttp.Handler())
	http.HandleFunc("/track", handler)

	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}

	log.Printf("Starting server on port %s", port)
	if err := http.ListenAndServe(":"+port, nil); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}